this is the code in class Enterprise in my clicker game: @override
  void recalculateMaxoutQuantity() {
    final q = multimerch.quantity;

    const n = EnterpriseData.next;
    final b = _bank.funds;

    if (costNext > b) {
      _maxoutQuantity = 0;
    } else if (costNext == b) {
      _maxoutQuantity = 1;
    } else {
      _maxoutQuantity =
          (log(pow(n, q.toDouble()) + ((b * (n - 1)) / (costPerUnit))) / log(n))
                  .floor() -
              q;
    }

    // Constrain maxout purchase quantity to limit

    if (_maxoutQuantity > quantityLimit) {
      _maxoutQuantity = quantityLimit - q;
    }
  }

  @override
  void recalculateMaxoutPricetag() {
    double pricetag;

    if (_maxoutQuantity == 0 || _maxoutQuantity == 1) {
      pricetag = costNext;
    } else {
      pricetag = EnterpriseData.getEnterpriseCostOfPurchase(
          costPerUnit, multimerch.quantity, _maxoutQuantity);
    }

    _maxoutPricetag = pricetag;
  }

static double getEnterpriseCostOfPurchase(
      double baseCost, int baseQuantity, int amount) {
    final double cost = (baseCost *
            (pow(next, (baseQuantity + amount).toDouble()).toDouble() -
                pow(next, baseQuantity.toDouble()).toDouble()) /
            (next - 1))
        .roundToDouble();

    return cost;
  }

/// Try to spend [amount] from bank.
  /// If successful funds are spent and returns true,
  /// otherwise funds are kept and returns false
  @override
  bool spend(double amount) {
    if (amount <= 0 || amount.isInfinite || amount.isNaN) return false;

    if (amount > funds) {
      if (GameSession.instance.debug.gratisPurchasing) {
        earnCheated(amount - funds);
        // when purchasing gratias, earn lacking funds
        // which are considered cheated
      } else {
        return false;
      }
    }

    _funds -= amount;

    _emitFundsChanged();

    return true;
  }

static const double baseClickingPower = 10;

  double _clickingPower = baseClickingPower;
  double get clickingPower => _clickingPower;

  void recalculateClickingPower() {
    _clickingPower = baseClickingPower;

    double afkMultiplier = 0;

    for (final u in clickerUpgrades) {
      if (u.singlemerch.purchased) afkMultiplier += u.upgradePower;
    }

    if (afkMultiplier != 0) {
      _clickingPower += _afk.incomeAfk * afkMultiplier;
    }

    onClickingPowerChanged.emit(this);
  }

class ClickerUpgrade with CanBeHidden, Upgrade {
  static const int implemented = 5;

  ClickerUpgrade._();
  factory ClickerUpgrade.create(
    Clicker c,
    int index,
  ) {
    final u = ClickerUpgrade._();
    u.createUpgrade(
      GameSession.instance.upgradeList,
      UpgradeType.clicker,
      c,
      index,
      _generateUpgradeClickerPricetag(index),
    );
    u.c = c;
    return u;
  }

  late final Clicker c;

  @override
  double get upgradePower {
    return 0.036 * (upgradeIndex + 1);
  }

  @override
  String get hint {
    String hint = '+';
    hint += '${upgradePower.asPercent()}% ';
    hint += I18n.m.upgradeHints.clicker;
    return hint;
  }

  @override
  String get name =>
      I18n.findMessage('upgradeNames.c.u${upgradeIndex.asWidth2}');
}
